  ('dietitian-moex-11649', 'dietitian', 'dietitian-moex-092-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '對於痛風患者，下列何種建議是「錯誤的」？ 避免飲酒過量    多攝食蔬菜及水果，使尿液偏鹼性 肥胖者應於短期間減輕體重，以緩和痛風症狀  多喝水，保持尿液在2公升以上，以排出尿酸', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "c2fd7358752e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
